import React from 'react';
import EyePanel from './components/EyePanel';
import PageBorder from './components/PageBorder';
import './App.css';

export default function App() {
  return (
    <div className="app">
      {/* left — eye bleeds off left edge */}
      <div className="eye-side">
        <EyePanel />
      </div>

      {/* right — brand */}
      <div className="text-side">
        <div className="brand">
          <span className="brand-word w1">ru</span>
          <span className="brand-word w2">shakti</span>
        </div>
        <p className="tagline">empowering strength · inspiring grace</p>
      </div>
    </div>
  );
}
